PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE controls (
	id INTEGER NOT NULL, 
	cis_id VARCHAR NOT NULL, 
	name VARCHAR NOT NULL, 
	objective TEXT, 
	implementation_guidance TEXT, 
	status VARCHAR, 
	risk_level VARCHAR, 
	owner_id INTEGER, 
	due_date DATE, 
	review_date DATE, 
	created_at DATETIME, 
	updated_at DATETIME, started_at DATETIME, implemented_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(owner_id) REFERENCES users (id)
);
COMMIT;

PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE safeguards (
	id INTEGER NOT NULL, 
	control_id INTEGER NOT NULL, 
	safeguard_id VARCHAR NOT NULL, 
	title VARCHAR NOT NULL, 
	description TEXT, 
	implementation_status VARCHAR, 
	ig VARCHAR NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(control_id) REFERENCES controls (id) ON DELETE CASCADE
);
COMMIT;

PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE evidence (
	id INTEGER NOT NULL, 
	control_id INTEGER NOT NULL, 
	uploaded_by INTEGER NOT NULL, 
	file_path VARCHAR, 
	file_name VARCHAR, 
	file_size INTEGER, 
	mime_type VARCHAR, 
	note TEXT, 
	external_link VARCHAR, 
	created_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(control_id) REFERENCES controls (id) ON DELETE CASCADE, 
	FOREIGN KEY(uploaded_by) REFERENCES users (id)
);
COMMIT;

PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE users (
	id INTEGER NOT NULL, 
	email VARCHAR NOT NULL, 
	hashed_password VARCHAR, 
	full_name VARCHAR NOT NULL, 
	is_active BOOLEAN, 
	mfa_enabled BOOLEAN, 
	created_at DATETIME, 
	updated_at DATETIME, external_id VARCHAR, 
	PRIMARY KEY (id)
);
COMMIT;

PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE settings (
	"key" VARCHAR NOT NULL, 
	value JSON, 
	updated_at DATETIME, 
	PRIMARY KEY ("key")
);
COMMIT;

PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE review_schedules (
	id INTEGER NOT NULL, 
	control_id INTEGER NOT NULL, 
	review_type VARCHAR NOT NULL, 
	next_review_at DATETIME NOT NULL, 
	last_reviewed_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(control_id) REFERENCES controls (id) ON DELETE CASCADE
);
COMMIT;

COMMIT;
