INSERT INTO controls VALUES(1,'1','Inventory and Control of Enterprise Assets','Actively manage (inventory, track, and correct) all enterprise assets (end-user devices, including portable and mobile; network devices; non-computing/IoT devices; and servers) connected to the infrastructure physically, virtually, remotely, and those within cloud environments, to accurately know the totality of assets that need to be monitored and protected within the enterprise. This will also support identifying unauthorized and unmanaged assets to remove or remediate.',NULL,'in_progress','critical',5,NULL,NULL,'2026-04-30 12:14:54.813902','2026-05-06 22:36:05.854018','2026-05-06 22:36:05.853843',NULL);
INSERT INTO controls VALUES(2,'2','Inventory and Control of Software Assets','Actively manage (inventory, track, and correct) all software (operating systems and applications) on the network so that only authorized software is installed and can execute, and that unauthorized and unmanaged software is found and prevented from installation or execution.',NULL,'in_progress','critical',5,NULL,NULL,'2026-04-30 12:14:54.814323','2026-05-06 22:36:05.860823','2026-05-06 22:36:05.860723',NULL);
INSERT INTO controls VALUES(3,'3','Data Protection','Develop processes and technical controls to identify, classify, securely handle, retain, and dispose of data.',NULL,'in_progress','high',5,NULL,NULL,'2026-04-30 12:14:54.815271','2026-05-06 22:36:05.868701','2026-05-06 22:36:05.868618',NULL);
INSERT INTO controls VALUES(4,'4','Secure Configuration of Enterprise Assets and Software','Establish and maintain the secure configuration of enterprise assets (end-user devices, including portable and mobile; network devices; non-computing/IoT devices; and servers) and software (operating systems and applications).',NULL,'in_progress','high',5,NULL,NULL,'2026-04-30 12:14:54.815701','2026-05-06 22:36:05.882022','2026-05-06 22:36:05.881935',NULL);
INSERT INTO controls VALUES(5,'5','Account Management','Use processes and tools to assign and manage authorization to credentials for user accounts, including administrator accounts, as well as service accounts, to enterprise assets and software.',NULL,'in_progress','high',5,NULL,NULL,'2026-04-30 12:14:54.816150','2026-05-06 22:36:05.891831','2026-05-06 22:36:05.891750',NULL);
INSERT INTO controls VALUES(6,'6','Access Control Management','Establish processes and tools to create, assign, manage, and revoke access credentials and privileges for user, administrator, and service accounts for enterprise assets and software.',NULL,'in_progress','high',5,NULL,NULL,'2026-04-30 12:14:54.816499','2026-05-06 22:36:05.897823','2026-05-06 22:36:05.897746',NULL);
INSERT INTO controls VALUES(7,'7','Continuous Vulnerability Management','Develop a plan to continuously assess and track vulnerabilities on all enterprise assets within the enterprise''s infrastructure, in order to remediate, and minimize, the window of opportunity for attackers. Monitor public and private industry sources for new vulnerability information.',NULL,'implemented','high',5,NULL,NULL,'2026-04-30 12:14:54.816825','2026-05-06 22:54:33.117713','2026-05-06 22:36:05.905527','2026-05-06 22:54:33.117623');
INSERT INTO controls VALUES(8,'8','Audit Log Management','Collect, alert, review, and retain audit logs of events that could help detect, understand, or recover from an attack.',NULL,'in_progress','medium',5,NULL,NULL,'2026-04-30 12:14:54.817174','2026-05-06 22:36:05.915371','2026-05-06 22:36:05.915280',NULL);
INSERT INTO controls VALUES(9,'9','Email and Web Browser Protections','Improve protections and detections via greater security controls of the enterprise''s email and web infrastructure.',NULL,'implemented','medium',5,NULL,NULL,'2026-04-30 12:14:54.817530','2026-05-06 22:54:33.137795','2026-05-06 22:36:05.927248','2026-05-06 22:54:33.137674');
INSERT INTO controls VALUES(10,'10','Malware Defenses','Prevent or control the installation, spread, and execution of malicious applications, code, or scripts on enterprise assets.',NULL,'in_progress','high',5,NULL,NULL,'2026-04-30 12:14:54.817927','2026-05-06 22:36:05.935489','2026-05-06 22:36:05.935403',NULL);
INSERT INTO controls VALUES(11,'11','Data Recovery','Establish and maintain data recovery practices sufficient to restore in-scope enterprise assets to a pre-incident and trusted state.',NULL,'in_progress','medium',5,NULL,NULL,'2026-04-30 12:14:54.818278','2026-05-06 22:54:33.146436','2026-05-06 22:36:05.943704',NULL);
INSERT INTO controls VALUES(12,'12','Network Infrastructure Management','Establish, implement, and actively manage (track, report on, correct) network devices, in order to prevent attackers from exploiting vulnerable network services and access points.',NULL,'in_progress','medium',5,NULL,NULL,'2026-04-30 12:14:54.818610','2026-05-06 22:36:05.947793','2026-05-06 22:36:05.947700',NULL);
INSERT INTO controls VALUES(13,'13','Network Monitoring and Defense','Operate processes and tooling to establish and maintain comprehensive network monitoring and defense against security threats across the enterprise''s network infrastructure and user base.',NULL,'in_progress','medium',5,NULL,NULL,'2026-04-30 12:14:54.818947','2026-05-06 22:36:05.956211','2026-05-06 22:36:05.956130',NULL);
INSERT INTO controls VALUES(14,'14','Security Awareness and Skills Training','Establish and maintain a security awareness program to influence behavior among the workforce to be security conscious and properly skilled to reduce cybersecurity risks to the enterprise.',NULL,'implemented','low',5,NULL,NULL,'2026-04-30 12:14:54.819342','2026-05-06 22:54:33.172858','2026-05-06 22:36:05.968103','2026-05-06 22:54:33.172768');
INSERT INTO controls VALUES(15,'15','Service Provider Management','Develop a process to evaluate service providers who hold sensitive data, or are responsible for an enterprise''s critical IT platforms or processes, to ensure these providers are protecting those platforms and data appropriately.',NULL,'in_progress','medium',5,NULL,NULL,'2026-04-30 12:14:54.819706','2026-05-06 22:36:05.977805','2026-05-06 22:36:05.977717',NULL);
INSERT INTO controls VALUES(16,'16','Application Software Security','Manage the security life cycle of in-house developed, hosted, or acquired software to prevent, detect, and remediate security weaknesses before they can impact the enterprise.',NULL,'in_progress','high',5,NULL,NULL,'2026-04-30 12:14:54.820039','2026-05-06 22:36:05.984117','2026-05-06 22:36:05.984036',NULL);
INSERT INTO controls VALUES(17,'17','Incident Response Management','Establish a program to develop and maintain an incident response capability (e.g., policies, plans, procedures, defined roles, training, and communications) to prepare, detect, and quickly respond to an attack.',NULL,'in_progress','high',5,NULL,NULL,'2026-04-30 12:14:54.820431','2026-05-06 22:36:05.997941','2026-05-06 22:36:05.997856',NULL);
INSERT INTO controls VALUES(18,'18','Penetration Testing','Test the effectiveness and resiliency of enterprise assets through identifying and exploiting weaknesses in controls (people, processes, and technology), and simulating the objectives and actions of an attacker.',NULL,'implemented','medium',7,NULL,NULL,'2026-04-30 12:14:54.820821','2026-05-06 22:54:33.204236','2026-05-06 22:36:06.006239','2026-05-06 22:54:33.204147');
INSERT INTO safeguards VALUES(1,1,'1.1','Establish and Maintain Detailed Enterprise Asset Inventory','Establish and maintain an accurate, detailed, and up-to-date inventory of all enterprise assets with the potential to store or process data, to include: end-user devices (including portable and mobile), network devices, non-computing/IoT devices, and servers. Ensure the inventory records the network address, hardware address, machine name, data asset owner, and department for each asset and whether the asset has been approved to connect to the network. Review and update the inventory of all enterprise assets bi-annually, or more frequently.','implemented_most','ig1');
INSERT INTO safeguards VALUES(2,1,'1.2','Address Unauthorized Assets','Ensure that unauthorized assets are either removed from the network, quarantined, or the inventory is updated in a timely manner.','implemented_all','ig1');
INSERT INTO safeguards VALUES(3,1,'1.3','Utilize an Active Discovery Tool','Utilize an active discovery tool to identify assets connected to the enterprise''s network. Configure the active discovery tool to execute daily, or more frequently.','implemented_all','ig2');
INSERT INTO safeguards VALUES(4,1,'1.4','Use Dynamic Host Configuration Protocol (DHCP) Logging to Update Asset Inventory','Use DHCP logging to update the enterprise''s asset inventory. Review and update the inventory mapping monthly, or more frequently.','not_implemented','ig2');
INSERT INTO safeguards VALUES(5,1,'1.5','Use a Passive Asset Discovery Tool','Use a passive discovery tool to identify assets connected to the enterprise''s network. Review and update the inventory of assets bi-annually, or more frequently.','implemented_all','ig3');
INSERT INTO safeguards VALUES(6,2,'2.1','Establish and Maintain a Software Inventory','Establish and maintain a detailed inventory of all licensed software installed on enterprise assets. The software inventory must document the title, publisher, initial install/use date, and business purpose for each installation; define the business cases allowed for installing any software; and identify the asset location and/or user for each installation. Review and update the software inventory bi-annually, or more frequently.','implemented_all','ig1');
INSERT INTO safeguards VALUES(7,2,'2.2','Ensure Authorized Software is Currently Supported','Ensure that only currently supported software is designated as authorized in the software inventory for enterprise assets. If software is unsupported, yet necessary for the fulfillment of the enterprise''s mission, document an exception detailing mitigating controls and a plan for replacement within 180 days. Review the software list to verify software support at least monthly, or more frequently.','implemented_all','ig1');
INSERT INTO safeguards VALUES(8,2,'2.3','Address Unauthorized Software','Ensure that unauthorized software is either removed from use on enterprise assets or receives a documented exception. Review monthly, or more frequently.','implemented_all','ig1');
INSERT INTO safeguards VALUES(9,2,'2.4','Utilize Automated Software Inventory Tools','Utilize software inventory tools, when possible, throughout the enterprise to automate the documentation of installed software on enterprise assets.','implemented_all','ig2');
INSERT INTO safeguards VALUES(10,2,'2.5','Allowlist Authorized Software','Use technical controls, such as application allowlisting, to ensure that only authorized software can execute or be accessed. Reassess bi-annually, or more frequently.','parts_implemented','ig2');
INSERT INTO safeguards VALUES(11,2,'2.6','Allowlist Authorized Libraries','Use technical controls to ensure that only authorized software libraries, such as specific .dll, .ocx, .so, etc., files, are allowed to load into a system process. Block unauthorized libraries from loading into a system process. Reassess bi-annually, or more frequently.','parts_implemented','ig3');
INSERT INTO safeguards VALUES(12,2,'2.7','Allowlist Authorized Scripts','Use technical controls, such as digital signatures and version control, to ensure that only authorized scripts, such as specific .ps1, .py, etc., files, are allowed to execute. Block unauthorized scripts from executing. Reassess bi-annually, or more frequently.','parts_implemented','ig3');
INSERT INTO safeguards VALUES(13,3,'3.1','Establish and Maintain a Data Management Process','Establish and maintain a data management process. In the process, address data sensitivity, data owner, handling of data, data retention limits, and disposal requirements, based on sensitivity and retention standards for the enterprise. Review and update the process annually, or when significant enterprise changes occur that could impact this Safeguard.','parts_implemented','ig1');
INSERT INTO safeguards VALUES(14,3,'3.2','Establish and Maintain a Data Inventory','Establish and maintain a data inventory, based on the enterprise''s data management process. Inventory sensitive data, at a minimum. Review and update the inventory annually, or when significant enterprise changes occur that could impact this Safeguard.','parts_implemented','ig1');
INSERT INTO safeguards VALUES(15,3,'3.3','Configure Data Access Control Lists','Configure access control lists based on a user''s need to know and ensure that access is set to deny by default. Review and update access control lists quarterly, or more frequently.','implemented_most','ig1');
INSERT INTO safeguards VALUES(16,3,'3.4','Enforce Data Retention','Retain data according to the enterprise''s data management process. Data retention must be outlined and follow compliance and regulatory requirements.','not_applicable','ig1');
INSERT INTO safeguards VALUES(17,3,'3.5','Securely Dispose of Data','Securely dispose of data as outlined in the enterprise''s data management process, but at least annually. Ensure the disposal process and method are commensurate with the data sensitivity.','not_implemented','ig1');
INSERT INTO safeguards VALUES(18,3,'3.6','Encrypt Data on End-User Devices','Encrypt data on end-user devices containing sensitive data. Example implementations can include: Windows BitLocker®, Apple FileVault®, Linux® dm-crypt.','implemented_all','ig2');
INSERT INTO safeguards VALUES(19,3,'3.7','Establish and Maintain a Data Classification Scheme','Establish and maintain an overall data classification scheme for the enterprise. Examples of data classification categories include: top secret, secret, confidential, sensitive, and public. Review and update the classification scheme annually, or when significant enterprise changes occur.','parts_implemented','ig2');
INSERT INTO safeguards VALUES(20,3,'3.8','Document Data Flows','Document data flows. Data flow documentation includes service provider data flows and should be based on the enterprise''s data management process. Review and update documentation annually, or when significant enterprise changes occur.','parts_implemented','ig2');
INSERT INTO safeguards VALUES(21,3,'3.9','Encrypt Data on Removable Media','Encrypt data on removable media.','not_implemented','ig2');
INSERT INTO safeguards VALUES(22,3,'3.10','Encrypt Sensitive Data in Transit','Encrypt sensitive data in transit. Example implementations include: Transport Layer Security (TLS) and Open Secure Shell (OpenSSH).','implemented_most','ig2');
INSERT INTO safeguards VALUES(23,3,'3.11','Encrypt Sensitive Data at Rest','Encrypt sensitive data at rest on servers, applications, and databases containing sensitive data. Storage-layer encryption, also known as server-side encryption, meets the minimum requirement of this Safeguard. Additional application-layer encryption of data can provide additional defense-in-depth.','implemented_most','ig2');
INSERT INTO safeguards VALUES(24,3,'3.12','Segment Data Processing and Storage Based on Sensitivity','Segment data processing and storage based on the sensitivity of the data. Do not process sensitive data on enterprise assets intended for lower sensitivity data.','implemented_all','ig3');
INSERT INTO safeguards VALUES(25,3,'3.13','Deploy a Data Loss Prevention Solution','Deploy a data loss prevention (DLP) solution on enterprise assets that monitor, detect, and block sensitive data exfiltration.','implemented_most','ig3');
INSERT INTO safeguards VALUES(26,3,'3.14','Log Sensitive Data Access','Log access to sensitive data. Example implementations include monitoring access to sensitive data on enterprise assets, and, for some enterprises, comprehensive logging on storage systems with sensitive data.','implemented_all','ig3');
INSERT INTO safeguards VALUES(27,4,'4.1','Establish and Maintain a Secure Configuration Process','Establish and maintain a secure configuration process for enterprise assets (end-user devices, including portable and mobile; non-computing/IoT devices; and servers) and software (operating systems and applications). Review and update documentation annually, or when significant enterprise changes occur that could impact this Safeguard.','implemented_most','ig1');
INSERT INTO safeguards VALUES(28,4,'4.2','Establish and Maintain a Secure Configuration Process for Network Infrastructure','Establish and maintain a secure configuration process for network devices. Review and update documentation annually, or when significant enterprise changes occur that could impact this Safeguard.','implemented_most','ig1');
INSERT INTO safeguards VALUES(29,4,'4.3','Configure Automatic Session Locking on Enterprise Assets','Configure automatic session locking on enterprise assets after a defined period of inactivity. For general purpose operating systems, the period must not exceed 15 minutes. For mobile end-user devices, the period must not exceed 2 minutes. For specific enterprise use cases, an approved exception can be defined, but the period must still not exceed the defined period in CIS Control 4.3.','implemented_all','ig1');
INSERT INTO safeguards VALUES(30,4,'4.4','Implement and Manage a Firewall on Servers','Implement and manage a host-based firewall or port-filtering tool on all servers, with a default-deny rule that drops all traffic except those services and ports that are explicitly allowed.','implemented_all','ig1');
INSERT INTO safeguards VALUES(31,4,'4.5','Implement and Manage a Firewall on End-User Devices','Implement and manage a host-based firewall or port-filtering tool on end-user devices, with a default-deny rule that drops all traffic except those services and ports that are explicitly allowed.','implemented_all','ig1');
INSERT INTO safeguards VALUES(32,4,'4.6','Securely Manage Enterprise Assets and Software','Securely manage enterprise assets and software. Example implementations include: restricting administrative privileges to a dedicated administrative account; using a separate password for the administrative account; and requiring multi-factor authentication for the administrative account.','implemented_all','ig2');
INSERT INTO safeguards VALUES(33,4,'4.7','Manage Default Accounts on Enterprise Assets and Software','Manage default accounts on enterprise assets and software, such as root, administrator, and other pre-configured vendor accounts. Example implementations can include: disabling default accounts or making them unusable.','implemented_most','ig2');
INSERT INTO safeguards VALUES(34,4,'4.8','Uninstall or Disable Unnecessary Services on Enterprise Assets and Software','Uninstall or disable unnecessary services on enterprise assets and software, such as an unused file sharing service, web application module, or service function.','parts_implemented','ig2');
INSERT INTO safeguards VALUES(35,4,'4.9','Configure Trusted DNS Servers on Enterprise Assets','Configure enterprise assets to use trusted DNS servers. Example implementations include: protecting assets from DNS hijacking by configuring trusted DNS servers and monitoring for changes.','implemented_all','ig3');
INSERT INTO safeguards VALUES(36,5,'5.1','Establish and Maintain an Inventory of Accounts','Establish and maintain an inventory of all accounts managed in the enterprise. The inventory, at a minimum, must contain the person''s name, username, the department for the account, and the date the account was granted access. Review and update the inventory of all accounts to confirm that all active accounts are authorized, on a routine, defined schedule, at least quarterly, or more frequently.','implemented_most','ig1');
INSERT INTO safeguards VALUES(37,5,'5.2','Use Unique Passwords','Use unique passwords for all enterprise assets. Best practice implementation includes, at a minimum, an 8-character password for accounts using multi-factor authentication (MFA) and a 14-character password for accounts not using MFA.','implemented_most','ig1');
INSERT INTO safeguards VALUES(38,5,'5.3','Disable Dormant Accounts','Delete or disable any dormant accounts after a period of 45 days of inactivity, where supported. Disable any dormant accounts that cannot be deleted.','implemented_all','ig1');
INSERT INTO safeguards VALUES(39,5,'5.4','Restrict Administrator Privileges to Dedicated Administrator Accounts','Restrict administrator privileges to dedicated administrator accounts on enterprise assets. Conduct general computing activities, such as internet browsing, email, and productivity suite use, from the user''s primary, non-privileged account.','implemented_most','ig1');
INSERT INTO safeguards VALUES(40,5,'5.5','Establish and Maintain an Inventory of Service Accounts','Establish and maintain an inventory of service accounts. The inventory, at a minimum, must contain the department owner, review date, and purpose. Perform service account reviews to validate that all active accounts are authorized, on a recurring schedule at least quarterly, or more frequently.','implemented_most','ig2');
INSERT INTO safeguards VALUES(41,5,'5.6','Centralize Account Management','Centralize account management through a directory service or SSO provider, where supported.','implemented_most','ig2');
INSERT INTO safeguards VALUES(42,6,'6.1','Establish an Access Granting Process','Establish and follow a process, preferably automated, for granting access to enterprise assets upon new hire, rights grant, or role change of a user.','implemented_most','ig1');
INSERT INTO safeguards VALUES(43,6,'6.2','Establish an Access Revoking Process','Establish and follow a process, preferably automated, for revoking access to enterprise assets, upon termination, rights revocation, or role change of a user.','implemented_most','ig1');
INSERT INTO safeguards VALUES(44,6,'6.3','Require MFA for Externally-Exposed Applications','Require all externally-exposed enterprise or third-party applications to enforce MFA, where supported. Enforcing MFA through a directory service or SSO provider qualifies as implementing this safeguard.','implemented_most','ig1');
INSERT INTO safeguards VALUES(45,6,'6.4','Require MFA for Remote Network Access','Require MFA for remote access to the enterprise''s network, where supported.','implemented_most','ig1');
INSERT INTO safeguards VALUES(46,6,'6.5','Require MFA for Administrative Access','Require MFA for all administrative access accounts, where supported, on all enterprise assets and software, managed and on-premises, regardless of whether the asset or software is accessed remotely or locally.','implemented_most','ig1');
INSERT INTO safeguards VALUES(47,6,'6.6','Establish and Maintain an Inventory of Authentication and Authorization Systems','Establish and maintain an inventory of the enterprise''s authentication and authorization systems, including those hosted on-site or by a third-party provider. Review and update the inventory annually, or when significant enterprise changes occur that could impact this Safeguard.','implemented_most','ig2');
INSERT INTO safeguards VALUES(48,6,'6.7','Centralize Access Control','Centralize access control for all enterprise assets through a directory service or SSO provider, where supported.','implemented_most','ig2');
INSERT INTO safeguards VALUES(49,6,'6.8','Define and Maintain Role-Based Access Control','Define and maintain role-based access control, through determining and documenting the access rights necessary for each role within the enterprise to effectively carry out its assigned duties. Perform access control reviews of enterprise assets to validate that all privileges are authorized, on a recurring schedule at least quarterly, or more frequently.','implemented_most','ig3');
INSERT INTO safeguards VALUES(50,7,'7.1','Establish and Maintain a Vulnerability Management Process','Establish and maintain a documented vulnerability management process for enterprise assets. Review and update documentation annually, or when significant enterprise changes occur that could impact this Safeguard.','implemented_all','ig1');
INSERT INTO safeguards VALUES(51,7,'7.2','Establish and Maintain a Remediation Process','Establish and maintain a risk-based remediation strategy documented in a remediation process, with monthly, or more frequent, reviews.','implemented_all','ig1');
INSERT INTO safeguards VALUES(52,7,'7.3','Perform Automated Operating System Patch Management','Perform operating system updates on enterprise assets through automated patch management on a monthly, or more frequent, basis.','implemented_all','ig1');
INSERT INTO safeguards VALUES(53,7,'7.4','Perform Automated Application Patch Management','Perform application updates on enterprise assets through automated patch management on a monthly, or more frequent, basis.','implemented_all','ig1');
INSERT INTO safeguards VALUES(54,7,'7.5','Perform Automated Vulnerability Scans of Internal Enterprise Assets','Perform automated vulnerability scans of internal enterprise assets on a quarterly, or more frequent, basis. Conduct both authenticated and unauthenticated scans.','implemented_all','ig2');
INSERT INTO safeguards VALUES(55,7,'7.6','Perform Automated Vulnerability Scans of Externally-Exposed Enterprise Assets','Perform automated vulnerability scans of externally-exposed enterprise assets on a quarterly, or more frequent, basis. Conduct both authenticated and unauthenticated scans.','implemented_all','ig2');
INSERT INTO safeguards VALUES(56,7,'7.7','Remediate Detected Vulnerabilities','Remediate detected vulnerabilities in software through processes on a monthly, or more frequent, basis, based on the remediation process.','implemented_all','ig2');
INSERT INTO safeguards VALUES(57,8,'8.1','Establish and Maintain an Audit Log Management Process','Establish and maintain an audit log management process that defines the enterprise''s logging requirements. At a minimum, address the types of logs to be retained, resources to allocate, and the log retention time frame. Review and update documentation annually, or when significant enterprise changes occur that could impact this Safeguard.','implemented_most','ig1');
INSERT INTO safeguards VALUES(58,8,'8.2','Collect Audit Logs','Collect audit logs. Ensure that logging, per the enterprise''s audit log management process, has been enabled and is configured per enterprise requirements.','implemented_most','ig1');
INSERT INTO safeguards VALUES(59,8,'8.3','Ensure Adequate Audit Log Storage','Ensure that the storage capacity for the enterprise''s audit logs is large enough to retain audit logs per the enterprise''s audit log management process.','implemented_most','ig1');
INSERT INTO safeguards VALUES(60,8,'8.4','Standardize Time Synchronization','Standardize time synchronization. Configure enterprise assets to use time synchronization. At a minimum, enterprise assets should be configured to use the enterprise''s time synchronization infrastructure.','implemented_most','ig1');
INSERT INTO safeguards VALUES(61,8,'8.5','Collect Detailed Audit Logs','Configure detailed audit logging for enterprise assets containing sensitive data. Include event source, date, username, timestamp, source addresses, destination addresses, and other useful elements that could assist in a forensic investigation.','implemented_most','ig2');
INSERT INTO safeguards VALUES(62,8,'8.6','Collect DNS Query Audit Logs','Collect DNS query audit logs. Configure the logging to include the source IP address, destination IP address, and query name.','implemented_most','ig2');
INSERT INTO safeguards VALUES(63,8,'8.7','Collect URL Request Audit Logs','Collect URL request audit logs on enterprise assets, where appropriate and supported, to include source IP, destination IP, destination port, and timestamp.','implemented_most','ig2');
INSERT INTO safeguards VALUES(64,8,'8.8','Collect Command-Line Audit Logs','Collect command-line audit logs. Example implementations include collecting audit logs from PowerShell®, Bash®, and cmd.exe.','implemented_most','ig2');
INSERT INTO safeguards VALUES(65,8,'8.9','Centralize Audit Logs','Centralize, to the extent possible, audit log collection and retention across enterprise assets.','implemented_most','ig2');
INSERT INTO safeguards VALUES(66,8,'8.10','Retain Audit Logs','Retain audit logs across enterprise assets for a minimum of 90 days.','implemented_most','ig2');
INSERT INTO safeguards VALUES(67,8,'8.11','Conduct Audit Log Reviews','Conduct reviews of audit logs to detect anomalies or abnormal events that could indicate a potential threat. Conduct reviews on a weekly, or more frequent, basis. If possible, utilize automation.','implemented_most','ig3');
INSERT INTO safeguards VALUES(68,8,'8.12','Collect Service Provider Logs','Collect service provider logs, where supported, to maintain visibility over service provider actions on enterprise assets.','implemented_most','ig3');
INSERT INTO safeguards VALUES(69,9,'9.1','Ensure Use of Only Fully Supported Browsers and Email Clients','Ensure only fully supported browsers and email clients are allowed to execute in the enterprise, only using the latest version of browsers and email clients provided through the vendor.','implemented_all','ig1');
INSERT INTO safeguards VALUES(70,9,'9.2','Use DNS Filtering Services','Use DNS filtering services on all enterprise assets to block access to known malicious domains.','implemented_all','ig1');
INSERT INTO safeguards VALUES(71,9,'9.3','Maintain and Enforce Network-Based URL Filters','Enforce and update network-based URL filters to limit an enterprise asset from connecting to potentially malicious or unapproved websites. Example implementations include category-based filtering, reputation-based filtering, or through the use of block lists. Enforce filters for all enterprise assets.','implemented_all','ig1');
INSERT INTO safeguards VALUES(72,9,'9.4','Restrict Unnecessary or Unauthorized Browser and Email Client Extensions','Restrict installation of unnecessary or unauthorized browser or email client extensions, add-ins, or plug-ins.','implemented_all','ig1');
INSERT INTO safeguards VALUES(73,9,'9.5','Implement DMARC','Implement Domain-based Message Authentication, Reporting, and Conformance (DMARC) and enable receiver-side reporting. At a minimum, implement a DMARC policy of p=none. As DMARC matures, progress to a DMARC policy of quarantine and eventually reject.','implemented_all','ig2');
INSERT INTO safeguards VALUES(74,9,'9.6','Block Unnecessary File Types','Block unnecessary file types attempting to enter the enterprise''s email gateway.','implemented_all','ig2');
INSERT INTO safeguards VALUES(75,9,'9.7','Deploy and Maintain Email Server Anti-Malware Protections','Deploy and maintain anti-malware software on all email servers.','implemented_all','ig2');
INSERT INTO safeguards VALUES(76,10,'10.1','Deploy and Maintain Anti-Malware Software','Deploy and maintain anti-malware software on all enterprise assets.','implemented_most','ig1');
INSERT INTO safeguards VALUES(77,10,'10.2','Configure Automatic Anti-Malware Signature Updates','Configure automatic updates for anti-malware signature files on all enterprise assets.','implemented_all','ig1');
INSERT INTO safeguards VALUES(78,10,'10.3','Disable Autorun and Autoplay for Removable Media','Disable autorun and autoplay auto-execute capabilities for removable media.','implemented_all','ig1');
INSERT INTO safeguards VALUES(79,10,'10.4','Configure Automatic Anti-Malware Scanning of Removable Media','Configure anti-malware software to automatically scan removable media upon connection.','implemented_all','ig2');
INSERT INTO safeguards VALUES(80,10,'10.5','Enable Anti-Exploitation Features','Enable anti-exploitation features, such as Data Execution Prevention (DEP), Address Space Layout Randomization (ASLR), virtualization/containerization, etc.','implemented_all','ig2');
INSERT INTO safeguards VALUES(81,10,'10.6','Centrally Manage Anti-Malware Software','Centrally manage anti-malware software.','implemented_all','ig2');
INSERT INTO safeguards VALUES(82,10,'10.7','Use Behavior-Based Anti-Malware Software','Use behavior-based anti-malware software.','implemented_all','ig3');
INSERT INTO safeguards VALUES(83,11,'11.1','Establish and Maintain a Data Recovery Process','Establish and maintain a data recovery process. In the process, address the scope of data recovery activities, recovery prioritization, and the security of backup data. Review and update documentation annually, or when significant enterprise changes occur that could impact this Safeguard.','not_implemented','ig1');
INSERT INTO safeguards VALUES(84,11,'11.2','Perform Automated Backups','Perform automated backups of in-scope enterprise assets. Run backups weekly, or more frequently. Recover data, at a minimum, quarterly, by conducting data restoration processes to verify backup integrity.','implemented_most','ig1');
INSERT INTO safeguards VALUES(85,11,'11.3','Protect Recovery Data','Protect recovery data with equivalent controls to the original data. Apply access controls, encryption, and isolation to backup data.','implemented_most','ig1');
INSERT INTO safeguards VALUES(86,11,'11.4','Establish and Maintain an Isolated Instance of Recovery Data','Establish and maintain an isolated instance of recovery data. Example implementations include, version controlling backup data through cloud solutions or air-gapping local backup instances.','not_implemented','ig2');
INSERT INTO safeguards VALUES(87,11,'11.5','Test Data Recovery','Test data recovery quarterly, or more frequently, from backup data.','not_implemented','ig3');
INSERT INTO safeguards VALUES(88,12,'12.1','Ensure Network Infrastructure is Up-to-Date','Ensure network infrastructure is kept up-to-date. Example implementations include running the latest stable release of software and/or currently supported by the vendor.','implemented_all','ig1');
INSERT INTO safeguards VALUES(89,12,'12.2','Establish and Maintain a Secure Network Architecture','Establish and maintain a secure network architecture. A secure network architecture must address segmentation, least privilege, and availability, at a minimum.','implemented_all','ig1');
INSERT INTO safeguards VALUES(90,12,'12.3','Securely Manage Network Infrastructure','Securely manage network infrastructure. Example implementations include the use of secure protocols such as HTTPS and SSH, and multi-factor authentication for administrative access.','implemented_all','ig1');
INSERT INTO safeguards VALUES(91,12,'12.4','Establish and Maintain Architecture Diagram(s)','Establish and maintain architecture diagram(s) and/or other network system documentation. Review and update documentation annually, or when significant enterprise changes occur that could impact this Safeguard.','implemented_all','ig2');
INSERT INTO safeguards VALUES(92,12,'12.5','Centralize Network Authentication, Authorization, and Auditing (AAA)','Centralize network AAA.','implemented_most','ig2');
INSERT INTO safeguards VALUES(93,12,'12.6','Use of Secure Network Management and Communication Protocols','Use secure network management and communication protocols. Use secure protocols such as SSH and HTTPS for the management and administration of network infrastructure. Disable unnecessary or insecure protocols.','implemented_all','ig2');
INSERT INTO safeguards VALUES(94,12,'12.7','Ensure Remote Devices Utilize a VPN and Are Connecting to an Enterprise''s AAA Infrastructure','Require users to authenticate to enterprise-managed VPN and authentication services prior to accessing enterprise resources on end-user devices.','implemented_most','ig2');
INSERT INTO safeguards VALUES(95,12,'12.8','Establish and Maintain Dedicated Computing Resources for All Administrative Work','Establish and maintain dedicated computing resources, either physically or logically separated, for all administrative tasks or tasks requiring administrative access. The enterprise must only use these dedicated computing resources for any task requiring administrative access.','implemented_all','ig3');
INSERT INTO safeguards VALUES(96,13,'13.1','Centralize Security Event Alerting','Centralize security event alerting. Enterprise detection, prevention, and alerting systems must be integrated to provide a single point of view for all enterprise alerting.','implemented_most','ig1');
INSERT INTO safeguards VALUES(97,13,'13.2','Deploy a Host-Based Intrusion Detection Solution','Deploy a host-based intrusion detection solution on enterprise assets, where appropriate and/or supported.','implemented_most','ig2');
INSERT INTO safeguards VALUES(98,13,'13.3','Deploy a Network Intrusion Detection Solution','Deploy a network intrusion detection solution on enterprise assets, where appropriate. Example implementations include the use of a Network Intrusion Detection System (NIDS) or equivalent cloud service provider (CSP) solution.','implemented_most','ig2');
INSERT INTO safeguards VALUES(99,13,'13.4','Perform Traffic Filtering Between Network Segments','Perform traffic filtering between network segments, where appropriate.','implemented_most','ig2');
INSERT INTO safeguards VALUES(100,13,'13.5','Manage Access Control for Remote Assets','Manage access control for assets remotely connecting to enterprise resources. Determine and document the enterprise''s access requirements for all remote assets. Example implementations include: using a separate administrative account for remote access and limiting which users can connect remotely.','implemented_most','ig2');
INSERT INTO safeguards VALUES(101,13,'13.6','Collect Network Traffic Flow Logs','Collect network traffic flow logs and/or network traffic to assist in the investigation of abnormal network activity.','implemented_most','ig2');
INSERT INTO safeguards VALUES(102,13,'13.7','Deploy a Host-Based Intrusion Prevention Solution','Deploy a host-based intrusion prevention solution on enterprise assets, where appropriate and/or supported. Example implementations include the use of Endpoint Detection and Response (EDR) solutions.','implemented_most','ig3');
INSERT INTO safeguards VALUES(103,13,'13.8','Deploy a Network Intrusion Prevention Solution','Deploy a network intrusion prevention solution, where appropriate. Example implementations include the use of a Network Intrusion Prevention System (NIPS) or equivalent CSP solution.','implemented_most','ig3');
INSERT INTO safeguards VALUES(104,13,'13.9','Deploy Port-Level Access Control','Deploy port-level access control, where appropriate. Port-level access control can be implemented via 802.1x, or equivalent technologies.','implemented_most','ig3');
INSERT INTO safeguards VALUES(105,13,'13.10','Perform Application Layer Filtering','Perform application layer filtering. Example implementations include the use of Proxies or Web Application Firewalls (WAF).','implemented_most','ig3');
INSERT INTO safeguards VALUES(106,13,'13.11','Tune Security Event Alerting Thresholds','Tune security event alerting thresholds, on a monthly, or more frequent, basis.','implemented_most','ig3');
INSERT INTO safeguards VALUES(107,14,'14.1','Establish and Maintain a Security Awareness Program','Establish and maintain a security awareness program. The purpose of a security awareness program is to educate the enterprise''s workforce on how to interact with enterprise assets and data in a secure manner. Conduct training at hire and, at a minimum, annually. Review and update content annually, or when significant enterprise changes occur that could impact this Safeguard.','implemented_all','ig1');
INSERT INTO safeguards VALUES(108,14,'14.2','Train Workforce Members to Recognize Social Engineering Attacks','Train workforce members to recognize social engineering attacks, such as phishing, pre-texting, and tailgating.','implemented_all','ig1');
INSERT INTO safeguards VALUES(109,14,'14.3','Train Workforce Members on Authentication Best Practices','Train workforce members on authentication best practices. Example topics include MFA, password composition, and credential management.','implemented_all','ig1');
INSERT INTO safeguards VALUES(110,14,'14.4','Train Workforce on Data Handling Best Practices','Train workforce members on how to identify and properly store, transfer, archive, or destroy sensitive information.','implemented_all','ig1');
INSERT INTO safeguards VALUES(111,14,'14.5','Train Workforce Members on Causes of Unintentional Data Exposure','Train workforce members to be aware of causes for unintentional data exposures. Example topics include the risk of emailing clear text passwords or sensitive data as an attachment, or the risk of not locking their computer when they step away.','implemented_all','ig1');
INSERT INTO safeguards VALUES(112,14,'14.6','Train Workforce Members on Recognizing and Reporting Security Incidents','Train workforce members to be able to recognize a potential incident and be able to report such an incident.','implemented_all','ig1');
INSERT INTO safeguards VALUES(113,14,'14.7','Train Workforce on How to Identify and Report if Their Enterprise Assets are Missing Security Updates','Train workforce members on how to identify and report if their enterprise assets are missing security updates, have antivirus signatures that are out-of-date, or have not been recently scanned.','implemented_all','ig2');
INSERT INTO safeguards VALUES(114,14,'14.8','Train Workforce on the Dangers of Connecting to and Transmitting Enterprise Data Over Insecure Networks','Train workforce members on the dangers of connecting to, and transmitting data over, insecure networks (e.g., public Wi-Fi). In addition, train workforce members on the procedures to ensure that the remote connections and data transmissions are performed in a secure manner.','implemented_all','ig2');
INSERT INTO safeguards VALUES(115,14,'14.9','Conduct Role-Specific Security Awareness and Skills Training','Conduct role-specific security awareness and skills training. Example implementations include secure application development training for software engineers, or training for incident response teams.','implemented_all','ig3');
INSERT INTO safeguards VALUES(116,15,'15.1','Establish and Maintain an Inventory of Service Providers','Establish and maintain an inventory of service providers. The inventory must record the service provided, the type of service, and the contact. Review and update the inventory annually, or when significant enterprise changes occur that could impact this Safeguard.','parts_implemented','ig2');
INSERT INTO safeguards VALUES(117,15,'15.2','Establish and Maintain a Service Provider Management Policy','Establish and maintain a service provider management policy. Ensure the policy requires service providers to undergo a security assessment, and that contractual language is in place to ensure the right to audit. Review and update the policy annually, or when significant enterprise changes occur that could impact this Safeguard.','parts_implemented','ig2');
INSERT INTO safeguards VALUES(118,15,'15.3','Classify Service Providers','Classify service providers. Classification consideration must include one or more characteristics, such as data sensitivity, criticality of the service, or access to the enterprise''s network. Review and update classifications annually, or when significant enterprise changes occur that could impact this Safeguard.','implemented_all','ig2');
INSERT INTO safeguards VALUES(119,15,'15.4','Ensure Service Provider Contracts Include Security Requirements','Ensure service provider contracts include security requirements, such as a right-to-audit clause, to address access, handling, and ownership of enterprise''s data.','implemented_most','ig2');
INSERT INTO safeguards VALUES(120,15,'15.5','Assess Service Providers','Assess service providers annually to ensure they are meeting their contractual obligations. Review the results and document any issues in a deviation request.','implemented_most','ig2');
INSERT INTO safeguards VALUES(121,15,'15.6','Monitor Service Provider Security Practices','Monitor service provider security practices on a recurring basis to ensure security controls are implemented and operating as intended.','not_implemented','ig2');
INSERT INTO safeguards VALUES(122,15,'15.7','Securely Decommission Service Providers','Securely decommission service providers. Example implementations include ensuring that data and enterprise assets are returned or destroyed in a secure manner.','not_implemented','ig3');
INSERT INTO safeguards VALUES(123,15,'15.8','Establish and Maintain Service Provider Data Transmission Policy','Establish and maintain a service provider data transmission policy. The policy must include requirements for encryption and data integrity, and it must address access to enterprise data. Review and update the policy annually, or when significant enterprise changes occur that could impact this Safeguard.','not_implemented','ig3');
INSERT INTO safeguards VALUES(124,15,'15.9','Establish and Maintain Service Provider Asset Policy','Establish and maintain a service provider asset policy. The policy must identify whether the service provider or the enterprise owns the asset, the asset''s location, and the return or destruction process. Review and update the policy annually, or when significant enterprise changes occur that could impact this Safeguard.','not_implemented','ig3');
INSERT INTO safeguards VALUES(125,16,'16.1','Establish and Maintain a Secure Application Development Process','Establish and maintain a secure application development process. In the process, address such items as: secure application design standards, secure coding practices, developer training, vulnerability management, code review, and application security testing. Review and update the process at least annually, or when significant enterprise changes occur that could impact this Safeguard.','implemented_all','ig2');
INSERT INTO safeguards VALUES(126,16,'16.2','Establish and Maintain a Process to Accept and Address Software Vulnerabilities','Establish and maintain a process to accept and address reports of software vulnerabilities, including reports from the public. As part of the process, designate a point of contact for the public to submit vulnerability reports.','implemented_most','ig2');
INSERT INTO safeguards VALUES(127,16,'16.3','Perform Root Cause Analysis on Security Vulnerabilities','Perform root cause analysis on security vulnerabilities. When possible, address the root cause of the vulnerability and not the symptom.','implemented_most','ig2');
INSERT INTO safeguards VALUES(128,16,'16.4','Establish and Manage an Inventory of Third-Party Software Components','Establish and manage an updated inventory of third-party components used in development, often called a ''Software Bill of Materials'' (SBOM), as well as components embedded in enterprise software. Review and update the inventory annually, or when significant enterprise changes occur that could impact this Safeguard.','not_applicable','ig2');
INSERT INTO safeguards VALUES(129,16,'16.5','Use Up-to-Date and Trusted Third-Party Software Components','Use up-to-date and trusted third-party software components. Use software components from trusted repositories. When using such repositories, validate the legitimacy of components prior to use.','not_applicable','ig2');
INSERT INTO safeguards VALUES(130,16,'16.6','Establish and Maintain a Severity Rating System and Process for Application Vulnerabilities','Establish and maintain a severity rating system and process for application vulnerabilities that facilitates the prioritization of order-of-remediation based on the impact to the business. Review and update the system and process annually.','implemented_most','ig2');
INSERT INTO safeguards VALUES(131,16,'16.7','Use Standard Hardening Configuration Templates for Application Infrastructure','Use standard hardening configuration templates for application infrastructure. Implement via the use of Infrastructure as Code (IaC).','parts_implemented','ig2');
INSERT INTO safeguards VALUES(132,16,'16.8','Separate Production and Non-Production Systems','Maintain separate environments for production and non-production systems.','implemented_all','ig2');
INSERT INTO safeguards VALUES(133,16,'16.9','Train Developers in Application Security Concepts and Secure Coding','Train developers in application security concepts and secure coding. Conduct training at hire and annually. Review and update training annually, or when significant enterprise changes occur that could impact this Safeguard.','implemented_all','ig2');
INSERT INTO safeguards VALUES(134,16,'16.10','Apply Secure Design Principles in Application Architectures','Apply secure design principles in application architectures. Secure design principles include the concept of least privilege and enforcing mediation to validate every operation that the user makes, prioritizing fail-safe defaults, and minimizing attack surface area.','implemented_most','ig2');
INSERT INTO safeguards VALUES(135,16,'16.11','Leverage Vetted Modules or Services for Application Security Components','Leverage vetted modules or services for application security components, such as user authentication, access control, and encryption.','implemented_most','ig2');
INSERT INTO safeguards VALUES(136,16,'16.12','Implement Code-Level Security Checks','Implement code-level security checks. Example implementations include static application security testing (SAST), dynamic application security testing (DAST), and software composition analysis (SCA).','implemented_most','ig2');
INSERT INTO safeguards VALUES(137,16,'16.13','Conduct Application Penetration Testing','Conduct application penetration testing. For critical applications, authenticated penetration testing is better suited to finding business logic vulnerabilities than code scanning and automated security testing.','implemented_most','ig3');
INSERT INTO safeguards VALUES(138,16,'16.14','Conduct Threat Modeling','Conduct threat modeling. Threat modeling is a form of risk assessment that models aspects of the attack and defense sides of a logical entity, such as a piece of data, an application, a component, a function, or a service.','implemented_most','ig3');
INSERT INTO safeguards VALUES(139,17,'17.1','Designate Personnel to Manage Incident Handling','Designate one key person, and at least one backup, who will manage the enterprise''s incident handling process. Management personnel are responsible for the oversight of all components of incident handling, including but not limited to: containment and eradication, and risk assessment, and are to be contacted in the event of an incident.','implemented_most','ig1');
INSERT INTO safeguards VALUES(140,17,'17.2','Establish and Maintain Contact Information for Reporting Security Incidents','Establish and maintain contact information for parties that need to be informed of security incidents. Contacts may include internal staff and external entities, such as: service providers, vendors, and law enforcement. Review and update contacts annually, or when significant enterprise changes occur that could impact this Safeguard.','implemented_most','ig1');
INSERT INTO safeguards VALUES(141,17,'17.3','Establish and Maintain an Enterprise Process for Reporting Incidents','Establish and maintain an enterprise process for the workforce to report security incidents. The process must include workforce members reporting sensitive data spills, lost/stolen portable end-user devices and paper files, potential malware infections, and any other security incidents. Review and update documentation annually, or when significant enterprise changes occur that could impact this Safeguard.','implemented_most','ig1');
INSERT INTO safeguards VALUES(142,17,'17.4','Establish and Maintain an Incident Response Process','Establish and maintain an incident response process that addresses roles and responsibilities, compliance requirements, and communication plans. Example implementations can be based on established frameworks (e.g., NIST SP 800-61r2). Review and update documentation annually, or when significant enterprise changes occur that could impact this Safeguard.','implemented_most','ig1');
INSERT INTO safeguards VALUES(143,17,'17.5','Assign Key Roles and Responsibilities for Incident Response','Assign key roles and responsibilities for incident response, including but not limited to: containment, eradication, and recovery. Assign roles and responsibilities so that all personnel involved in incident response know what is expected of them.','implemented_most','ig1');
INSERT INTO safeguards VALUES(144,17,'17.6','Define Mechanisms for Communicating During Incident Response','Define mechanisms for communicating during incident response. Example implementations include: establishing out-of-band communication channels and having the capability to preserve communications.','implemented_most','ig2');
INSERT INTO safeguards VALUES(145,17,'17.7','Conduct Routine Incident Response Tabletop Exercises','Conduct routine incident response tabletop exercises. Exercises must be conducted at a routine frequency, at least annually, and involve personnel that have a role in the incident response process.','not_implemented','ig2');
INSERT INTO safeguards VALUES(146,17,'17.8','Conduct Post-Incident Reviews','Conduct post-incident reviews. Reviews must include identifying the root cause and the steps to prevent the incident from happening again.','not_implemented','ig2');
INSERT INTO safeguards VALUES(147,17,'17.9','Establish and Maintain Security Incident Thresholds','Establish and maintain security incident thresholds. Example implementations include establishing a severity rating for incidents, and establishing a process for prioritizing incidents based on the severity rating.','not_implemented','ig3');
INSERT INTO safeguards VALUES(148,18,'18.1','Establish and Maintain a Penetration Testing Program','Establish and maintain a penetration testing program appropriate to the size, complexity, and maturity of the enterprise. Penetration testing program characteristics include scope, such as network, web application, Application Programming Interface (API), hosted services, and physical premise controls; frequency; limitations, such as acceptable hours, and excluded attack types; point of contact information; remediation, such as how findings will be routed; and retrospective requirements. Review and update the penetration testing program annually, or when significant enterprise changes occur that could impact this Safeguard.','implemented_all','ig2');
INSERT INTO safeguards VALUES(149,18,'18.2','Perform Periodic Internal Penetration Tests','Perform periodic internal penetration tests based on program requirements, no less than bi-annually. The testing may be black box or white box as needed.','implemented_all','ig2');
INSERT INTO safeguards VALUES(150,18,'18.3','Remediate Penetration Test Findings','Remediate penetration test findings. It is important to prioritize and implement the appropriate remediation based on the enterprise''s risk tolerance and the risk rating of the finding.','implemented_all','ig2');
INSERT INTO safeguards VALUES(151,18,'18.4','Validate Security Measures','Validate security measures after the remediation of penetration test findings.','implemented_all','ig3');
INSERT INTO safeguards VALUES(152,18,'18.5','Perform Periodic External Penetration Tests','Perform periodic external penetration tests based on program requirements, no less than bi-annually. External penetration testing must include enterprise and environmental reconnaissance to detect exploitable information. Penetration testing requires specialized skills and experience and must be conducted through a qualified party. The testing may be black box or white box as needed.','implemented_all','ig3');
